26→	function statusColor(status: string) {
27→		switch (status) {
28→			case 'pending': return 'var(--yellow)';
29→			case 'approved': return 'var(--green)';
30→			case 'denied': return 'var(--red)';
31→			case 'modified': return 'var(--orange)';
32→			default: return 'var(--text-muted)';
33→		}
34→	}
35→</script>
