321→// holdForApproval queues a tool call for later execution and returns a
322→// pending-approval response to the agent.
323→func (g *gateway) holdForApproval(ctx context.Context, qualifiedName string, route toolRoute, arguments map[string]any, decision model.Decision) toolResult {
324→	// Create an approval request if orchestrator is available.
325→	approvalID := ""
326→	if g.approvals != nil {
327→		rationale := "Policy requires approval"
328→		if len(decision.MatchedPolicies) > 0 {
329→			rationale = decision.MatchedPolicies[0].Explanation
330→		}
331→
332→		appr, err := g.approvals.Request(ctx, approval.ApprovalRequest{
333→			IntentID:    fmt.Sprintf("tool-call-%s-%d", qualifiedName, g.queue.len()),
334→			WorkspaceID: g.workspaceID,
335→			Rationale:   rationale,
336→		})
337→		if err != nil {
338→			g.log.Error("failed to create approval request", "tool", qualifiedName, "error", err)
339→			return toolResult{
340→				Content: []toolContent{{Type: "text", Text: fmt.Sprintf("Failed to create approval: %v", err)}},
341→				IsError: true,
342→			}
343→		}
344→		approvalID = appr.ApprovalID
345→	} else {
346→		// No orchestrator — generate a placeholder ID.
347→		approvalID = fmt.Sprintf("apr_pending_%d", g.queue.len())
348→	}
349→
350→	// Queue the original call for auto-execution after approval.
351→	g.queue.enqueue(approvalID, queuedCall{
352→		ServerName:    route.serverName,
353→		ToolName:      route.originalName,
354→		QualifiedName: qualifiedName,
355→		Arguments:     arguments,
356→	})
357→
358→	g.log.Info("tool call held for approval",
359→		"tool", qualifiedName,
360→		"approval_id", approvalID,
361→	)
362→
363→	return jsonResult(map[string]any{
364→		"status":      "pending_approval",
365→		"approval_id": approvalID,
366→		"message":     fmt.Sprintf("This action requires human approval. Use %s with the approval_id to check status.", checkApprovalTool),
367→		"tool":        qualifiedName,
368→	})
369→}
370→
371→// handleCheckApproval checks an approval's status and, if approved,
372→// auto-executes the queued tool call.
373→func (g *gateway) handleCheckApproval(ctx context.Context, args map[string]any) toolResult {
374→	approvalID := argStr(args, "approval_id")
375→	if approvalID == "" {
376→		return errorResult("approval_id is required")
377→	}
378→
379→	// Check if we have a queued call for this approval.
380→	call, queued := g.queue.peek(approvalID)
381→	if !queued {
382→		return jsonResult(map[string]any{
383→			"approval_id": approvalID,
384→			"status":      "not_found",
385→			"message":     "No pending tool call found for this approval ID.",
386→		})
387→	}
388→
389→	// Check the approval status via the orchestrator.
390→	if g.approvals != nil {
391→		appr, err := g.approvals.Get(ctx, approvalID)
392→		if err != nil {
393→			return jsonResult(map[string]any{
394→				"approval_id": approvalID,
395→				"status":      "error",
396→				"message":     fmt.Sprintf("Failed to check approval: %v", err),
397→			})
398→		}
399→
400→		switch appr.Status {
401→		case approval.StatusPending:
402→			return jsonResult(map[string]any{
403→				"approval_id": approvalID,
404→				"status":      "pending",
405→				"message":     "Still waiting for human approval.",
406→				"tool":        call.QualifiedName,
407→			})
408→
409→		case approval.StatusDenied:
410→			g.queue.dequeue(approvalID)
411→			return toolResult{
412→				Content: []toolContent{{Type: "text", Text: fmt.Sprintf("Action denied: %s → %s", call.summary(), approvalID)}},
413→				IsError: true,
414→			}
415→
416→		case approval.StatusApproved, approval.StatusModified:
417→			// Approved — auto-execute the queued call.
418→			return g.executeQueuedCall(ctx, approvalID)
419→
420→		default:
421→			return jsonResult(map[string]any{
422→				"approval_id": approvalID,
423→				"status":      string(appr.Status),
424→				"message":     fmt.Sprintf("Approval status: %s", appr.Status),
425→			})
426→		}
427→	}
428→
429→	// No orchestrator — the call stays queued until manually managed.
430→	return jsonResult(map[string]any{
431→		"approval_id": approvalID,
432→		"status":      "pending",
433→		"message":     "Waiting for approval. No approval orchestrator configured.",
434→		"tool":        call.QualifiedName,
435→	})
436→}
437→
438→// executeQueuedCall dequeues and forwards a previously held tool call.
439→func (g *gateway) executeQueuedCall(ctx context.Context, approvalID string) toolResult {
440→	call, ok := g.queue.dequeue(approvalID)
441→	if !ok {
442→		return errorResult("queued call not found for approval: " + approvalID)
443→	}
444→
445→	route, ok := g.routes[call.QualifiedName]
446→	if !ok {
447→		return errorResult("downstream server no longer available for tool: " + call.QualifiedName)
448→	}
449→
450→	g.log.Info("auto-executing approved tool call",
451→		"tool", call.QualifiedName,
452→		"approval_id", approvalID,
453→	)
454→
455→	return g.forwardToDownstream(ctx, route, call.Arguments)
456→}
