458→// closeAll terminates all downstream client connections and logs each shutdown.
459→func (g *gateway) closeAll() {
460→	for _, c := range g.clients {
461→		g.log.Info("closing downstream server", "name", c.Name())
462→		if err := c.Close(); err != nil {
463→			g.log.Warn("error closing downstream server",
464→				"name", c.Name(),
465→				"error", err,
466→			)
467→		}
468→	}
469→}
470→
471→// Shutdown gracefully shuts down the gateway, closing all downstream
472→// connections. The provided context can be used to set a deadline.
473→func (g *gateway) Shutdown(ctx context.Context) {
474→	g.log.Info("gateway shutdown starting")
475→
476→	done := make(chan struct{})
477→	go func() {
478→		g.closeAll()
479→		close(done)
480→	}()
481→
482→	select {
483→	case <-done:
484→		g.log.Info("gateway shutdown complete")
485→	case <-ctx.Done():
486→		g.log.Warn("gateway shutdown timed out", "error", ctx.Err())
487→	}
488→}
