490→// resolveEnv resolves vault:// prefixed env values using the vault, or
491→// passes them through unchanged. If vault is nil, vault:// references are
492→// treated as an error.
493→func resolveEnv(ctx context.Context, env map[string]string, v vault.Vault) (map[string]string, error) {
494→	if len(env) == 0 {
495→		return nil, nil
496→	}
497→
498→	vaultGet := func(path string) ([]byte, error) {
499→		if v == nil {
500→			return nil, fmt.Errorf("vault not available; cannot resolve vault://%s", path)
501→		}
502→		secret, err := v.Get(ctx, path)
503→		if err != nil {
504→			return nil, err
505→		}
506→		return secret.Value, nil
507→	}
508→
509→	return config.ResolveVaultEnv(env, vaultGet)
510→}
