527→// toSchema converts a generic map (from MCP tools/list) to our schema type.
528→func toSchema(raw map[string]any) schema {
529→	if raw == nil {
530→		return schema{Type: "object"}
531→	}
532→
533→	s := schema{Type: "object"}
534→
535→	if t, ok := raw["type"].(string); ok {
536→		s.Type = t
537→	}
538→
539→	if props, ok := raw["properties"].(map[string]any); ok {
540→		s.Properties = make(map[string]schemaProp, len(props))
541→		for name, v := range props {
542→			prop := schemaProp{}
543→			if pm, ok := v.(map[string]any); ok {
544→				if t, ok := pm["type"].(string); ok {
545→					prop.Type = t
546→				}
547→				if d, ok := pm["description"].(string); ok {
548→					prop.Description = d
549→				}
550→			}
551→			s.Properties[name] = prop
552→		}
553→	}
554→
555→	if req, ok := raw["required"].([]any); ok {
556→		for _, r := range req {
557→			if rs, ok := r.(string); ok {
558→				s.Required = append(s.Required, rs)
559→			}
560→		}
561→	}
562→
563→	return s
564→}
