22→func (s *CredentialStore) Create(_ context.Context, cred api.CredentialReference) error {
23→	s.mu.Lock()
24→	defer s.mu.Unlock()
25→	s.credentials[cred.CredentialId] = cred
26→	return nil
27→}
28→
29→func (s *CredentialStore) Get(_ context.Context, credentialID string) (api.CredentialReference, error) {
30→	s.mu.RLock()
31→	defer s.mu.RUnlock()
32→	c, ok := s.credentials[credentialID]
33→	if !ok {
34→		return api.CredentialReference{}, &store.ErrNotFound{Entity: "credential", ID: credentialID}
35→	}
36→	return c, nil
37→}
