39→func (s *CredentialStore) List(_ context.Context, filter store.CredentialFilter) ([]api.CredentialReference, error) {
40→	s.mu.RLock()
41→	defer s.mu.RUnlock()
42→	var result []api.CredentialReference
43→	for _, c := range s.credentials {
44→		if filter.WorkspaceID != "" && c.WorkspaceId != filter.WorkspaceID {
45→			continue
46→		}
47→		result = append(result, c)
48→	}
49→	return result, nil
