  1→// Package mcpclient provides a Go client that speaks Model Context Protocol (MCP)
  2→// over stdio to downstream MCP servers running as subprocesses.
  3→//
  4→// Communication uses newline-delimited JSON-RPC 2.0 over the subprocess's
  5→// stdin (requests) and stdout (responses).
  6→package mcpclient
  7→
  8→import (
  9→	"bufio"
 10→	"context"
 11→	"encoding/json"
 12→	"fmt"
 13→	"io"
 14→	"os"
 15→	"os/exec"
 16→	"sync"
 17→	"sync/atomic"
 18→	"syscall"
 19→	"time"
 20→
 21→	"github.com/ALRubinger/aileron/core/mcp"
 22→)
 23→
 24→// Client manages a connection to a single downstream MCP server subprocess.
 25→type Client struct {
 26→	name   string
 27→	cmd    *exec.Cmd
 28→	stdin  io.WriteCloser
 29→	stdout *bufio.Reader
 30→	mu     sync.Mutex // protects writes to stdin and reads from stdout
 31→	tools  []mcp.ToolDef
 32→	nextID int64
 33→}
 34→
 35→// JSON-RPC 2.0 wire types (internal).
 36→
 37→type jsonrpcRequest struct {
 38→	JSONRPC string `json:"jsonrpc"`
 39→	ID      any    `json:"id,omitempty"`
 40→	Method  string `json:"method"`
 41→	Params  any    `json:"params,omitempty"`
 42→}
 43→
 44→type jsonrpcResponse struct {
 45→	JSONRPC string          `json:"jsonrpc"`
 46→	ID      json.RawMessage `json:"id,omitempty"`
 47→	Result  json.RawMessage `json:"result,omitempty"`
 48→	Error   *jsonrpcError   `json:"error,omitempty"`
 49→}
 50→
 51→type jsonrpcError struct {
 52→	Code    int    `json:"code"`
 53→	Message string `json:"message"`
 54→}
 55→
 56→func (e *jsonrpcError) Error() string {
 57→	return fmt.Sprintf("jsonrpc error %d: %s", e.Code, e.Message)
 58→}
 59→
 60→// NewClient spawns a downstream MCP server as a subprocess and performs the
 61→// MCP initialize handshake. The command slice must contain at least the
 62→// program name; additional elements are passed as arguments. The env slice
 63→// is merged with os.Environ() so the subprocess inherits the current
 64→// environment plus any overrides.
 65→func NewClient(ctx context.Context, name string, command []string, env []string) (*Client, error) {
 66→	if len(command) == 0 {
 67→		return nil, fmt.Errorf("mcpclient: command must not be empty")
 68→	}
 69→
 70→	cmd := exec.CommandContext(ctx, command[0], command[1:]...)
 71→	cmd.Env = append(os.Environ(), env...)
 72→	cmd.Stderr = os.Stderr
 73→
 74→	stdinPipe, err := cmd.StdinPipe()
 75→	if err != nil {
 76→		return nil, fmt.Errorf("mcpclient: stdin pipe: %w", err)
 77→	}
 78→
 79→	stdoutPipe, err := cmd.StdoutPipe()
 80→	if err != nil {
 81→		return nil, fmt.Errorf("mcpclient: stdout pipe: %w", err)
 82→	}
 83→
 84→	if err := cmd.Start(); err != nil {
 85→		return nil, fmt.Errorf("mcpclient: start %q: %w", command[0], err)
 86→	}
 87→
 88→	c := &Client{
 89→		name:   name,
 90→		cmd:    cmd,
 91→		stdin:  stdinPipe,
 92→		stdout: bufio.NewReader(stdoutPipe),
 93→		nextID: 1, // 1 is reserved for the initialize request
 94→	}
 95→
 96→	// --- MCP initialize handshake ---
 97→
 98→	initParams := map[string]any{
 99→		"protocolVersion": "2024-11-05",
100→		"capabilities":    map[string]any{},
101→		"clientInfo": map[string]any{
102→			"name":    "aileron-gateway",
103→			"version": "0.0.1",
104→		},
105→	}
106→
107→	_, err = c.sendRequest("initialize", initParams)
108→	if err != nil {
109→		// Best-effort cleanup on failure.
110→		_ = c.Close()
111→		return nil, fmt.Errorf("mcpclient: initialize handshake: %w", err)
112→	}
113→
114→	// Send the initialized notification (no ID — it's a notification).
115→	if err := c.sendNotification("notifications/initialized"); err != nil {
116→		_ = c.Close()
117→		return nil, fmt.Errorf("mcpclient: initialized notification: %w", err)
118→	}
119→
120→	// Discover available tools.
121→	if _, err := c.DiscoverTools(ctx); err != nil {
122→		_ = c.Close()
123→		return nil, fmt.Errorf("mcpclient: discover tools: %w", err)
124→	}
125→
126→	return c, nil
127→}
128→
129→// DiscoverTools sends a tools/list request and caches the result.
130→func (c *Client) DiscoverTools(_ context.Context) ([]mcp.ToolDef, error) {
131→	raw, err := c.sendRequest("tools/list", nil)
132→	if err != nil {
133→		return nil, err
134→	}
135→
136→	var envelope struct {
137→		Tools []mcp.ToolDef `json:"tools"`
138→	}
139→	if err := json.Unmarshal(raw, &envelope); err != nil {
140→		return nil, fmt.Errorf("mcpclient: parse tools/list result: %w", err)
141→	}
142→
143→	c.tools = envelope.Tools
144→	return c.tools, nil
145→}
146→
147→// CallTool invokes a tool on the downstream MCP server by name.
148→func (c *Client) CallTool(_ context.Context, name string, arguments map[string]any) (*mcp.ToolResult, error) {
149→	params := map[string]any{
150→		"name":      name,
151→		"arguments": arguments,
152→	}
153→
154→	raw, err := c.sendRequest("tools/call", params)
155→	if err != nil {
156→		return nil, err
157→	}
158→
159→	var result mcp.ToolResult
160→	if err := json.Unmarshal(raw, &result); err != nil {
161→		return nil, fmt.Errorf("mcpclient: parse tools/call result: %w", err)
162→	}
163→
164→	return &result, nil
165→}
166→
167→// Tools returns the cached list of tools discovered from the server.
168→func (c *Client) Tools() []mcp.ToolDef {
169→	return c.tools
170→}
171→
172→// Name returns the human-readable name of this client connection.
173→func (c *Client) Name() string {
174→	return c.name
175→}
176→
177→// Close terminates the subprocess. It sends SIGTERM first, then SIGKILL
178→// after a 5-second timeout if the process hasn't exited.
179→func (c *Client) Close() error {
180→	if c.cmd == nil || c.cmd.Process == nil {
181→		return nil
182→	}
183→
184→	// Close stdin so the subprocess sees EOF.
185→	_ = c.stdin.Close()
186→
187→	// Send SIGTERM.
188→	if err := c.cmd.Process.Signal(syscall.SIGTERM); err != nil {
189→		// Process may have already exited; just wait.
190→		_ = c.cmd.Wait()
191→		return nil
192→	}
193→
194→	// Wait up to 5 seconds for graceful exit.
195→	done := make(chan error, 1)
196→	go func() {
197→		done <- c.cmd.Wait()
198→	}()
199→
200→	select {
201→	case err := <-done:
202→		return err
203→	case <-time.After(5 * time.Second):
204→		_ = c.cmd.Process.Kill()
205→		return <-done
206→	}
207→}
208→
209→// nextRequestID returns a monotonically increasing request ID.
210→func (c *Client) nextRequestID() int64 {
211→	return atomic.AddInt64(&c.nextID, 1)
212→}
213→
214→// sendRequest sends a JSON-RPC request and waits for the corresponding
215→// response. It returns the raw "result" field on success.
216→func (c *Client) sendRequest(method string, params any) (json.RawMessage, error) {
217→	c.mu.Lock()
218→	defer c.mu.Unlock()
219→
220→	id := c.nextRequestID()
221→	req := jsonrpcRequest{
222→		JSONRPC: "2.0",
223→		ID:      id,
224→		Method:  method,
225→		Params:  params,
226→	}
227→
228→	data, err := json.Marshal(req)
229→	if err != nil {
230→		return nil, fmt.Errorf("mcpclient: marshal request: %w", err)
231→	}
232→
233→	// Write newline-delimited JSON.
234→	if _, err := fmt.Fprintf(c.stdin, "%s\n", data); err != nil {
235→		return nil, fmt.Errorf("mcpclient: write request: %w", err)
236→	}
237→
238→	resp, err := c.readResponse()
239→	if err != nil {
240→		return nil, err
241→	}
242→
243→	if resp.Error != nil {
244→		return nil, resp.Error
245→	}
246→
247→	return resp.Result, nil
248→}
249→
250→// sendNotification sends a JSON-RPC notification (no ID, no response expected).
251→func (c *Client) sendNotification(method string) error {
252→	c.mu.Lock()
253→	defer c.mu.Unlock()
254→
255→	req := jsonrpcRequest{
256→		JSONRPC: "2.0",
257→		Method:  method,
258→	}
259→
260→	data, err := json.Marshal(req)
261→	if err != nil {
262→		return fmt.Errorf("mcpclient: marshal notification: %w", err)
263→	}
264→
265→	if _, err := fmt.Fprintf(c.stdin, "%s\n", data); err != nil {
266→		return fmt.Errorf("mcpclient: write notification: %w", err)
267→	}
268→
269→	return nil
270→}
271→
272→// readResponse reads one newline-delimited JSON line from the subprocess
273→// stdout and parses it as a JSON-RPC response.
274→func (c *Client) readResponse() (*jsonrpcResponse, error) {
275→	line, err := c.stdout.ReadBytes('\n')
276→	if err != nil {
277→		return nil, fmt.Errorf("mcpclient: read response: %w", err)
278→	}
279→
280→	var resp jsonrpcResponse
281→	if err := json.Unmarshal(line, &resp); err != nil {
282→		return nil, fmt.Errorf("mcpclient: parse response: %w (raw: %s)", err, string(line))
283→	}
284→
285→	return &resp, nil
286→}
