29→func (s *ConnectorStore) Get(_ context.Context, connectorID string) (api.Connector, error) {
30→	s.mu.RLock()
31→	defer s.mu.RUnlock()
32→	c, ok := s.connectors[connectorID]
33→	if !ok {
34→		return api.Connector{}, &store.ErrNotFound{Entity: "connector", ID: connectorID}
