39→func (s *ConnectorStore) List(_ context.Context, filter store.ConnectorFilter) ([]api.Connector, error) {
40→	s.mu.RLock()
41→	defer s.mu.RUnlock()
42→	var result []api.Connector
43→	for _, c := range s.connectors {
44→		if filter.WorkspaceID != "" && c.WorkspaceId != filter.WorkspaceID {
45→			continue
46→		}
47→		if filter.Type != nil && c.Type != *filter.Type {
48→			continue
49→		}
50→		result = append(result, c)
51→	}
52→	return result, nil
53→}
