		local := api.Local
		req.Mode = &local
	}

	if err := s.mcpServers.Create(r.Context(), req); err != nil {
		writeError(w, http.StatusInternalServerError, "internal_error", err.Error())
		return
	}
	writeJSON(w, http.StatusCreated, req)
}

